  return labels[value] ?? value
}

function formatRange(low: number | null | undefined, high: number | null | undefined): string {
  if (low == null && high == null) return '—'
  if (low != null && high != null) return `${low.toLocaleString()}–${high.toLocaleString()}`
  if (low != null) return `${low.toLocaleString()}+`
  return `≤${high!.toLocaleString()}`
}

// ── Sub-components ──────────────────────────────────────────────────────────

function DetailRow({ label, value }: { label: string; value: string }) {
  if (value === '—') return null
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Text size="sm" fw={500}>
        {value}
      </Text>
    </Group>
  )
}

function LinkRow({ label, url }: { label: string; url: string | null | undefined }) {
  if (!url) return null
  const href = url.startsWith('http') ? url : `https://${url}`
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Anchor href={href} target="_blank" rel="noopener noreferrer" size="sm" fw={500}>
        {url}
      </Anchor>
    </Group>
  )
}

function SectionHeader({ children }: { children: string }) {
  return (
    <Text size="xs" fw={700} tt="uppercase" c="dimmed" mb="xs">
      {children}
    </Text>
  )
}

// ── Props ───────────────────────────────────────────────────────────────────

interface InstitutionDetailProps {
  institution: SearchInstitution | null
  opened: boolean
  onClose: () => void
}

// ── Component ───────────────────────────────────────────────────────────────

